const path = require('path');

// Load problems data from JSON file
const problemsDataPath = path.resolve(__dirname, '../../data/problems.json');
let problems = [];
try {
  const rawData = fs.readFileSync(problemsDataPath, 'utf8');
  problems = JSON.parse(rawData);
} catch (e) {
  problems = [];
}

/**
 * List problems with filtering, paging, sorting, and metadata.
 * @param {Object} options
 * @param {string} [options.difficulty] - Filter by difficulty (e.g. 'Easy', 'Medium', 'Hard')
 * @param {number} [options.limit=50] - Max number of results to return (max 50)
 * @param {boolean} [options.includeComponents=false] - Whether to include sorted componentLanguages
 * @returns {Object} result
 * {
 *   problems: Array,
 *   totalProblems: number,
 *   filteredCount: number,
 *   appliedLimit: number,
 *   difficultyBreakdown: { [difficulty]: number }
 * }
 */
function listProblems({ difficulty, limit = 50, includeComponents = false } = {}) {
  // Validate limit
  if (typeof limit !== 'number' || limit <= 0) {
    limit = 50;
  }
  if (limit > 50) {
    limit = 50;
  }

  // Compute difficulty breakdown for all problems
  const difficultyBreakdown = {};
  for (const p of problems) {
    if (p.difficulty) {
      difficultyBreakdown[p.difficulty] = (difficultyBreakdown[p.difficulty] || 0) + 1;
    }
  }

  // Filter by difficulty if provided
  let filteredProblems = problems;
  if (difficulty) {
    filteredProblems = problems.filter(p => p.difficulty === difficulty);
  }

  // Sort by roundId ascending (deterministic ordering)
  filteredProblems.sort((a, b) => {
    if (a.roundId === b.roundId) {
      // fallback sort by problemId to ensure deterministic order
      if (a.problemId < b.problemId) return -1;
      if (a.problemId > b.problemId) return 1;
      return 0;
    }
    return a.roundId - b.roundId;
  });

  // Apply limit
  const appliedLimit = Math.min(limit, filteredProblems.length);
  const limitedProblems = filteredProblems.slice(0, appliedLimit);

  // If includeComponents, add sorted componentLanguages array
  const problemsWithComponents = limitedProblems.map(p => {
    const copy = { ...p };
    if (includeComponents && Array.isArray(copy.componentLanguages)) {
      copy.componentLanguages = [...copy.componentLanguages].sort();
    }
    return copy;
  });

  return {
    problems: problemsWithComponents,
    totalProblems: problems.length,
    filteredCount: filteredProblems.length,
    appliedLimit,
    difficultyBreakdown
  };
}

module.exports = {
  listProblems
};
